const transporter = nodemailer.createTransport({
  host: process.env.SMTP_HOST,
  port: Number(process.env.SMTP_PORT),
  secure: process.env.SMTP_SECURE === "true",
  auth: {
    user: process.env.SMTP_USER,
    pass: process.env.SMTP_PASS,
  },
});

/* =========================
   SEND SECURITY EMAIL
   ========================= */
async function sendSecurityMail({ to, type, ip, device }) {
  try {
    const subject =
      type === "signup"
        ? "Security Alert: Signup Attempt"
        : "Security Alert: Login Attempt";

    const text = `
Hi,

A ${type.toUpperCase()} attempt was detected on your account.

📍 IP Address: ${ip}
🖥 Device: ${device}
🕒 Time: ${new Date().toLocaleString()}

If this was NOT you, please secure your account immediately.

– Ecosort Security
`;

    await transporter.sendMail({
      from: `"Ecosort Security" <${process.env.FROM_EMAIL}>`,
      to,
      subject,
      text,
    });
