import React, { useState } from 'react';
import { Mail, Lock, User as UserIcon, ArrowLeft, AlertCircle, Loader2, Database, Copy, CheckCircle, ChevronDown, ChevronUp, MailCheck } from 'lucide-react';
import { db } from '../services/db';
import { emailService } from '../services/email';
import { User } from '../types';

interface RegisterProps {
  onToggleAuth: () => void;
  onBackHome: () => void;
  onSuccess: (user: User) => void;
}

const Register: React.FC<RegisterProps> = ({ onToggleAuth, onBackHome, onSuccess }) => {
  const [username, setUsername] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const [showSetupGuide, setShowSetupGuide] = useState(false);
  const [manualSetupOpen, setManualSetupOpen] = useState(false);
  const [copied, setCopied] = useState(false);
  const [successUser, setSuccessUser] = useState<User | null>(null);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    if (!username || !email || !password) {
      setError('Please fill in all fields.');
      return;
    }

    setLoading(true);
    try {
      const existing = await db.findUserByEmail(email);
      if (existing) {
        setError('This email is already registered.');
        setLoading(false);
        return;
      }

      const newUser: User = {
        id: Math.random().toString(36).substr(2, 9),
        username,
        email,
        password,
        createdAt: new Date().toISOString()
      };

      await db.saveUser(newUser);
      db.setCurrentUser(newUser);

      // Trigger emails (Welcome email + Security Alert)
      // We run them in parallel but don't strictly wait for them to block the success state for too long
      // though for a "check your inbox" screen, waiting ensures they are "sent"
      await Promise.all([
        emailService.sendWelcomeEmail(newUser),
        emailService.sendSecurityAlert(newUser, 'signup')
      ]);

      setSuccessUser(newUser);
    } catch (err: any) {
      console.error("Signup error:", err);
      if (err.message.includes("RLS_ERROR") || err.message.includes("TABLE_MISSING")) {
        setError(err.message.includes("RLS_ERROR") 
          ? "Row Level Security (RLS) is blocking the database." 
          : "Database tables 'users' and 'scans' are missing.");
        setShowSetupGuide(true);
      } else {
        setError(err.message || 'Connection error. Please check your internet.');
      }
    } finally {
      setLoading(false);
    }
  };

  const sqlSetup = `-- 1. Table for login and signup details
CREATE TABLE IF NOT EXISTS public.users (
  id TEXT PRIMARY KEY,
  username TEXT NOT NULL,
  email TEXT UNIQUE NOT NULL,
  password TEXT NOT NULL,
  created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

-- 2. Table for item scanned details
CREATE TABLE IF NOT EXISTS public.scans (
  id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  item TEXT NOT NULL,
  category TEXT NOT NULL,
  confidence FLOAT NOT NULL,
  instructions TEXT NOT NULL,
  user_id TEXT REFERENCES public.users(id) ON DELETE CASCADE,
  created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

-- 3. Disable Security for immediate testing
ALTER TABLE public.users DISABLE ROW LEVEL SECURITY;
ALTER TABLE public.scans DISABLE ROW LEVEL SECURITY;`;

  const copyToClipboard = () => {
    navigator.clipboard.writeText(sqlSetup);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  if (successUser) {
    return (
      <div className="min-h-[80vh] flex items-center justify-center px-4 py-12">
        <div className="max-w-md w-full animate-in fade-in zoom-in duration-300">
          <div className="bg-gray-900 border border-gray-800 rounded-[40px] p-8 shadow-2xl text-center relative overflow-hidden">
            {/* Background decoration */}
            <div className="absolute top-0 left-0 w-full h-2 bg-gradient-to-r from-green-400 to-green-600"></div>

            <div className="w-24 h-24 bg-green-500/10 rounded-full flex items-center justify-center mx-auto mb-8 relative">
              <div className="absolute inset-0 bg-green-500/20 rounded-full animate-ping"></div>
              <MailCheck className="w-10 h-10 text-green-500 relative z-10" />
            </div>

            <h2 className="text-3xl font-bold mb-4">Check your inbox!</h2>
            <p className="text-gray-300 mb-8 leading-relaxed">
              We've sent a welcome email to <span className="text-white font-bold">{successUser.email}</span>. It contains everything you need to start your recycling journey.
            </p>

            <button 
              onClick={() => onSuccess(successUser)}
              className="w-full bg-green-600 hover:bg-green-500 text-white py-4 rounded-xl font-bold transition-all shadow-xl shadow-green-900/30 hover:scale-[1.02]"
            >
              Continue to Dashboard
            </button>

            <button 
              onClick={onBackHome}
              className="mt-6 text-sm text-gray-500 hover:text-white transition-colors"
            >
              Back to Home
            </button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-[80vh] flex items-center justify-center px-4 py-12">
      <div className="max-w-md w-full">
        <button 
          onClick={onBackHome}
          className="flex items-center text-gray-400 hover:text-white transition-colors mb-8 group"
        >
          <ArrowLeft className="w-4 h-4 mr-2 group-hover:-translate-x-1 transition-transform" />
          Back to Home
        </button>

        <div className="bg-gray-900 border border-gray-800 rounded-[40px] p-8 shadow-2xl relative overflow-hidden">
          <div className="text-center mb-10">
            <h2 className="text-3xl font-bold mb-2">Create Account</h2>
            <p className="text-gray-400">Join the waste management revolution</p>
          </div>

          {/* Database Setup Helper (Collapsible) */}
          <div className="mb-6">
            <button 
              onClick={() => setManualSetupOpen(!manualSetupOpen)}
              className="w-full flex items-center justify-between p-3 bg-gray-800/30 border border-gray-700/50 rounded-xl text-xs text-gray-300 hover:bg-gray-800/50 transition-colors"
            >
              <div className="flex items-center">
                <Database className="w-3.5 h-3.5 mr-2 text-blue-500" />
                <span>First time setup? Create tables</span>
              </div>
              {manualSetupOpen ? <ChevronUp className="w-3.5 h-3.5" /> : <ChevronDown className="w-3.5 h-3.5" />}
            </button>

            {(manualSetupOpen || showSetupGuide) && (
              <div className="mt-3 bg-blue-600/10 border border-blue-500/30 rounded-2xl p-5 text-xs animate-in slide-in-from-top-2">
                <p className="text-blue-400 font-bold mb-3">SQL to Create Your Tables:</p>
                <div className="relative group">
                  <pre className="bg-black/40 p-3 rounded-lg text-green-500 font-mono overflow-x-auto border border-gray-800 max-h-40">
                    {sqlSetup}
                  </pre>
                  <button 
                    onClick={copyToClipboard}
                    className="absolute top-2 right-2 p-1.5 bg-gray-800 rounded-lg hover:bg-gray-700 text-gray-300 transition-colors flex items-center"
                  >
                    {copied ? <CheckCircle className="w-3.5 h-3.5 text-green-500" /> : <Copy className="w-3.5 h-3.5" />}
                  </button>
                </div>
                <p className="mt-3 text-gray-400">Paste this into your Supabase SQL Editor and click Run.</p>
              </div>
            )}
          </div>

          {error && !showSetupGuide && (
            <div className="mb-6 p-4 bg-red-500/10 border border-red-500/20 rounded-2xl flex items-start text-red-400 text-sm">
              <AlertCircle className="w-4 h-4 mr-2 shrink-0 mt-0.5" />
              <p>{error}</p>
            </div>
          )}

          <form className="space-y-5" onSubmit={handleSubmit}>
            <div>
              <label className="block text-sm font-medium text-gray-400 mb-1.5">Username</label>
              <div className="relative">
                <UserIcon className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-500" />
                <input 
                  type="text" 
                  value={username}
                  onChange={(e) => setUsername(e.target.value)}
                  placeholder="Choose a username"
                  disabled={loading}
                  className="w-full bg-gray-800/50 border border-gray-700 rounded-xl py-3 pl-10 pr-4 focus:outline-none focus:border-green-500 transition-colors disabled:opacity-50"
                />
              </div>
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-400 mb-1.5">Email Address</label>
              <div className="relative">
                <Mail className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-500" />
                <input 
                  type="email" 
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  placeholder="name@example.com"
                  disabled={loading}
                  className="w-full bg-gray-800/50 border border-gray-700 rounded-xl py-3 pl-10 pr-4 focus:outline-none focus:border-green-500 transition-colors disabled:opacity-50"
                />
              </div>
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-400 mb-1.5">Password</label>
              <div className="relative">
                <Lock className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-500" />
                <input 
                  type="password" 
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  placeholder="Min. 6 characters"
                  disabled={loading}
                  className="w-full bg-gray-800/50 border border-gray-700 rounded-xl py-3 pl-10 pr-4 focus:outline-none focus:border-green-500 transition-colors disabled:opacity-50"
                />
              </div>
            </div>

            <button 
              type="submit" 
              disabled={loading}
              className="w-full bg-green-600 hover:bg-green-500 text-white py-3.5 rounded-xl font-bold transition-all shadow-xl shadow-green-900/20 flex items-center justify-center disabled:opacity-50 mt-2"
            >
              {loading ? <Loader2 className="w-5 h-5 animate-spin" /> : 'Create Account'}
            </button>
          </form>

          <p className="mt-8 text-center text-gray-400 text-sm border-t border-gray-800 pt-6">
            Already have an account?{' '}
            <button onClick={onToggleAuth} className="text-green-500 font-bold hover:underline">
              Sign In
            </button>
          </p>
        </div>
      </div>
    </div>
  );
};

